#include<cstdio>
#include<vector>
#include<algorithm>
using namespace std;int W,H;char G[99][99];int nodes(char g[][99]){int c=0;for(int y=0;y<H;y++)for(int x=0;x<W;x++)if(g[y][x]=='@')c++;return c;}int boom(char g[][99],int bx,int by,char ng[][99]){for(int y=0;y<H;y++)for(int x=0;x<W;x++)ng[y][x]=g[y][x];int h=0;if(ng[by][bx]=='@'){ng[by][bx]='.';h++;}int dx[]={1,-1,0,0},dy[]={0,0,1,-1};for(int d=0;d<4;d++)for(int i=1;i<=3;i++){int x=bx+dx[d]*i,y=by+dy[d]*i;if(x<0||x>=W||y<0||y>=H||ng[y][x]=='#')break;if(ng[y][x]=='@'){ng[y][x]='.';h++;}}return h;}struct P{int x,y;};vector<P>plan;bool solve(char g[][99],int b,int t){if(!nodes(g))return 1;if(!b||t<3)return 0;vector<tuple<int,int,int>>cs;for(int y=0;y<H;y++)for(int x=0;x<W;x++)if(g[y][x]!='#'&&g[y][x]!='@'){char ng[99][99];int s=boom(g,x,y,ng);if(s>0)cs.push_back({-s,x,y});}sort(cs.begin(),cs.end());int lim=min((int)cs.size(),50);for(int i=0;i<lim;i++){auto[_,x,y]=cs[i];char ng[99][99];boom(g,x,y,ng);plan.push_back({x,y});if(solve(ng,b-1,t-3))return 1;plan.pop_back();}return 0;}int main(){scanf("%d%d",&W,&H);for(int y=0;y<H;y++)scanf("%s",G[y]);int pi=0;for(;;){int t,b;scanf("%d%d",&t,&b);if(pi>=plan.size())solve(G,b,t);if(pi<plan.size()){printf("%d %d\n",plan[pi].x,plan[pi].y);pi++;for(int i=0;i<2;i++){scanf("%d%d",&t,&b);puts("WAIT");}}else puts("WAIT");}}